class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        int onesInS = 0;
        for (char c : s) {
            if (c == '1') onesInS++;
        }
        return onesInS > 0 && onesInS < s.size() && target == "1";
    }
};
```

